import{_ as r,o as s,c as o,ag as n}from"./chunks/framework.WmBmIPw-.js";const p=JSON.parse('{"title":"禁忌搜索（Tabu Search, TS）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/tabu-search.md","filePath":"or-opt/tabu-search.md","lastUpdated":1777119486000}'),a={name:"or-opt/tabu-search.md"};function e(g,t,i,l,h,u){return s(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="禁忌搜索-tabu-search-ts" tabindex="-1">禁忌搜索（Tabu Search, TS） <a class="header-anchor" href="#禁忌搜索-tabu-search-ts" aria-label="Permalink to &quot;禁忌搜索（Tabu Search, TS）&quot;">​</a></h1><p>禁忌搜索在<strong>邻域搜索</strong>框架上引入<strong>短期记忆</strong>，结合<strong>渴望准则</strong>，在探索与利用之间折中。属单点、带记忆的元启发式，见 <a href="./metaheuristics.html">元启发式总览</a>。</p><p><strong>适用</strong>：组合优化（TSP、调度、图着色等）的近似求解；<strong>禁忌属性</strong>、<strong>tenure</strong> 与<strong>渴望</strong>的设计对效果影响大。</p><p><strong>核心</strong>：在「邻域可行情景」下，用禁忌表<strong>延缓</strong>对近期已犯移动的立即回退；在禁忌仍封锁优良移动时，用渴望准则<strong>破禁</strong>。</p><hr><h2 id="算法-最小化示意" tabindex="-1">算法（最小化示意） <a class="header-anchor" href="#算法-最小化示意" aria-label="Permalink to &quot;算法（最小化示意）&quot;">​</a></h2><p>以目标函数 f(s) 最小化叙述；与一次<strong>移动</strong> m 可关联的<strong>属性</strong>记为 a（如边、对换对等）。禁忌表在实现上可视为：近期被禁止的<strong>属性</strong>及其<strong>剩余禁忌步数</strong>的集合。</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 禁忌搜索主循环（单解、邻域 + 禁忌表）</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>选定初始解 s，记历史最优 s⋆ ← s。禁忌结构置空。设定：邻域算子、<strong>tenure</strong> 或其区间、最大迭代/时间、与渴望相关的参数。</p><h3 id="_2-邻域与筛选" tabindex="-1">2. 邻域与筛选 <a class="header-anchor" href="#_2-邻域与筛选" aria-label="Permalink to &quot;2. 邻域与筛选&quot;">​</a></h3><p>自当前 s 得候选集 N(s)（可采样）。对候选移动 m 得 s′ = m(s)。若 m 的<strong>属性</strong> a 仍处禁忌期，则 m 通常<strong>不入选</strong>，<strong>除非</strong> 满足下文「渴望准则」一节中预先声明的条件。</p><h3 id="_3-选择与移动" tabindex="-1">3. 选择与移动 <a class="header-anchor" href="#_3-选择与移动" aria-label="Permalink to &quot;3. 选择与移动&quot;">​</a></h3><p>在<strong>可接受</strong>候选中依规则选一步（如：存在改进步则选最优改进；否则选<strong>最小增</strong>的恶化步）。执行移动，更新 s。</p><h3 id="_4-更新禁忌与全局最优" tabindex="-1">4. 更新禁忌与全局最优 <a class="header-anchor" href="#_4-更新禁忌与全局最优" aria-label="Permalink to &quot;4. 更新禁忌与全局最优&quot;">​</a></h3><p>将本步<strong>属性</strong> a 入表，<strong>剩余步数</strong> 置为 tenure（或自区间随机等变体，见下文章节「禁忌表」）。若 f(s) &lt; f(s⋆)，令 s⋆ ← s。</p><h3 id="_5-终止" tabindex="-1">5. 终止 <a class="header-anchor" href="#_5-终止" aria-label="Permalink to &quot;5. 终止&quot;">​</a></h3><p>达迭代/时间/无改进步数等，或触发重启；输出 s⋆。</p></div><hr><h2 id="禁忌表-tabu-list" tabindex="-1">禁忌表（Tabu List） <a class="header-anchor" href="#禁忌表-tabu-list" aria-label="Permalink to &quot;禁忌表（Tabu List）&quot;">​</a></h2><p><strong>对象</strong>：表内通常不直接「禁止解向量本身」（维度过大），而禁止<strong>可逆、可标识</strong>的<strong>移动属性</strong> a；例如 TSP 中「边 (i, j) 刚被删除又立刻加回」、调度中「某工序对在相邻换位」等。同一邻域上<strong>属性与移动的抽取规则</strong>要一致，否则「禁忌了谁」在实现上会含糊。</p><p><strong>Recency 与 tenure</strong>：表维护的是<strong>近若干步内</strong>、或<strong>每属性剩余禁忌迭代数</strong>。</p><ul><li><strong>固定 tenure L</strong>：a 在入选后，连续 L 步内禁止<strong>再次</strong>出现「由该属性标识的逆移动」或相同属性再选（与邻域如何定义<strong>逆</strong>有关）。L 过短易短循环，过长易过度排斥合理探索。</li><li><strong>变长 tenure</strong>：在区间 [Lmin, Lmax] 上随机、或随搜索阶段调整，以减轻周期性与参数敏感。</li></ul><p><strong>实现形态</strong>：常采用<strong>循环队列/滑动窗口</strong>存最近 L 个属性，或<strong>每属性一计数</strong>每步减一直至 0 解禁；大邻域时可用<strong>子集</strong>评估候选、不必每次扫描全邻域（与 candidate list 思想衔接）。</p><p><strong>与邻域/逆移</strong>：禁忌针对的是「<strong>属性</strong>」在文献中有时对应「<strong>禁止逆移</strong>一定步数」；逆移的定义依赖编码（如 2-opt 的逆操作）。实现前应在问题说明里<strong>写清</strong>一条移动对应什么属性、逆移动对应何属性对。</p><h2 id="渴望准则-aspiration-criteria" tabindex="-1">渴望准则（Aspiration Criteria） <a class="header-anchor" href="#渴望准则-aspiration-criteria" aria-label="Permalink to &quot;渴望准则（Aspiration Criteria）&quot;">​</a></h2><p><strong>作用</strong>：在移动因禁忌被挡时，若该移动<strong>特别有价值</strong>，则<strong>允许破禁</strong>执行。否则禁忌表会机械地挡住<strong>全局最优</strong>邻域点，<strong>渴望</strong> 避免这一情形。</p><p><strong>经典准则（最常用）</strong>：若候选 s′ 满足 <strong>f(s′) &lt; f(s⋆)</strong>（带出新历史最优），则<strong>允许</strong> 即使对应移动属性仍在禁忌期也选用该步。这保证「有记录以来最好的解」不会被禁忌机械排除（在邻域能到达的前提下）。</p><p><strong>其他常见变体</strong>（可组合使用、按问题调参）：</p><ul><li><strong>按目标</strong>渴望：f(s′) 优于<strong>某一</strong>参考阈值（如本阶段最佳、加惩罚后的评价）。</li></ul><p><strong>注</strong>：破禁时仍应<strong>更新</strong>禁忌表与 s⋆ 的规则与常规步一致，并在日志中区分「渴望步」与「普通过步」便于调参复现。</p><h2 id="与同类方法的差异-提要" tabindex="-1">与同类方法的差异（提要） <a class="header-anchor" href="#与同类方法的差异-提要" aria-label="Permalink to &quot;与同类方法的差异（提要）&quot;">​</a></h2><ul><li>相对<strong>最速下降 / 贪心</strong>：允许无改进时选<strong>最小恶化</strong>移动，靠禁忌和渴望管理轨迹。</li><li>相对<strong>模拟退火</strong>：无随机接受温度，以<strong>显式</strong>禁忌与渴望<strong>替代</strong>部分随机性。</li><li>常作<strong>混合算法</strong>的一部分，或与大邻域、修复算子、精确子程序结合。</li></ul><h2 id="参考阅读" tabindex="-1">参考阅读 <a class="header-anchor" href="#参考阅读" aria-label="Permalink to &quot;参考阅读&quot;">​</a></h2><ul><li>Glover 关于 Tabu Search 的系列论文与专著；工业界综述、运筹教材中的「元启发式」章通常有<strong>禁忌表+渴望</strong> 的系统表述。</li><li>实现上务必为<strong>具体问题的编码、邻域、属性、逆移</strong> 单独定稿，并与代码注释一致，便于调参与复现。</li></ul>',25)])])}const d=r(a,[["render",e]]);export{p as __pageData,d as default};
